using Microsoft.ML;
using Microsoft.ML.Data;
using Microsoft.Extensions.ML;
using ChurnPredictor.Models;

var builder = WebApplication.CreateBuilder(args);

var mlContext = new MLContext(seed: 42);

var dataPath = Path.Combine("Data", "customers.csv");
var modelPath = Path.Combine("Data", "model.zip");

IDataView dataView = mlContext.Data.LoadFromTextFile<CustomerData>(
    dataPath, hasHeader: true, separatorChar: ',');

var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2);

// Map "Yes"/"No" to boolean Label
var labelMapping = new[] { new { Key = "Yes", Value = true }, { Key = "No", Value = false } };
var labelKeys = new[] { "Yes", "No" };
var labelValues = new[] { true, false };

var pipeline = mlContext.Transforms.Conversion.MapValue(
        "Label", new Dictionary<string, bool> { ["Yes"] = true, ["No"] = false },
        inputColumnName: "Churned")
    .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region"))
    .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "RegionEncoded", "PurchaseHistory"))
    .Append(mlContext.BinaryClassification.Trainers.FastTree());

var model = pipeline.Fit(split.TrainSet);

var predictions = model.Transform(split.TestSet);
var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");

Console.WriteLine($"Accuracy: {metrics.Accuracy:F4}");
Console.WriteLine($"AUC: {metrics.AreaUnderRocCurve:F4}");
Console.WriteLine($"F1: {metrics.F1Score:F4}");

mlContext.Model.Save(model, dataView.Schema, modelPath);

builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Prediction Service is running.");

app.MapPost("/predict", (PredictRequest request,
    PredictionEnginePool<CustomerData, ChurnPrediction> pool) =>
{
    var input = new CustomerData
    {
        Age = request.Age,
        Income = request.Income,
        Region = request.Region,
        PurchaseHistory = request.PurchaseHistory
    };

    var prediction = pool.Predict(input);

    return Results.Json(new
    {
        willChurn = prediction.PredictedLabel,
        probability = prediction.Probability
    });
});

app.MapGet("/metrics", () => Results.Json(new
{
    accuracy = metrics.Accuracy,
    auc = metrics.AreaUnderRocCurve,
    f1 = metrics.F1Score
}));

app.Run();

record PredictRequest(float Age, float Income, string Region, float PurchaseHistory);

